-- Seed quotes (30+ real memorable Peaky Blinders quotes)
INSERT INTO public.quotes (id, text, character, season, episode, episode_title, context, tags, mood, shelby_lesson) VALUES

-- Tommy Shelby quotes
('a0000001-0000-0000-0000-000000000001', 'Everyone''s a whore, Grace. We just sell different parts of ourselves.', 'Tommy Shelby', 1, 1, 'Episode 1', 'Tommy speaking to Grace at The Garrison pub about the nature of survival.', '{business,survival,philosophy}', 'reflective', 'Everyone compromises to survive. The question isn''t whether you make sacrifices—it''s whether you choose them consciously. Own your trade-offs instead of pretending they don''t exist.'),

('a0000001-0000-0000-0000-000000000002', 'I don''t pay for suits. My suits are on the house or the house burns down.', 'Tommy Shelby', 2, 1, 'Episode 1', 'Tommy asserting his authority with a tailor in Birmingham.', '{power,business,intimidation}', 'threatening', 'Confidence isn''t about being reckless—it''s about knowing your worth and refusing to accept less. When you bring real value, you set the terms.'),

('a0000001-0000-0000-0000-000000000003', 'Big fucks small. That''s the way it''s always been.', 'Tommy Shelby', 3, 1, 'Episode 1', 'Tommy explaining the brutal reality of power dynamics to a business partner.', '{power,business,reality}', 'defiant', 'Understanding power dynamics isn''t cynicism—it''s preparation. Know where you stand, then work to change your position.'),

('a0000001-0000-0000-0000-000000000004', 'I''m not a traitor to my class. I am just an extreme example of what a working man can achieve.', 'Tommy Shelby', 2, 6, 'Episode 6', 'Tommy defending his rise from the slums of Small Heath to a legitimate businessman.', '{ambition,class,pride}', 'defiant', 'Never apologize for your ambition. Rising above your circumstances isn''t betrayal—it''s proof that the ceiling others accept is just a suggestion.'),

('a0000001-0000-0000-0000-000000000005', 'In the bleak midwinter, I''ll make a bonfire of my enemies.', 'Tommy Shelby', 5, 6, 'Mr Jones', 'Tommy''s declaration during a moment of intense resolve.', '{revenge,determination,courage}', 'threatening', 'There are moments when the only way forward is through. Channel your adversity into fuel, not despair. The coldest seasons forge the strongest steel.'),

('a0000001-0000-0000-0000-000000000006', 'You can change what you do, but you can''t change what you want.', 'Tommy Shelby', 4, 1, 'The Noose', 'Tommy reflecting on his nature and his inability to leave the criminal life behind.', '{self-awareness,nature,philosophy}', 'reflective', 'Self-knowledge is the most honest form of power. You can redirect your drives, but denying them only gives them more control over you.'),

('a0000001-0000-0000-0000-000000000007', 'I have made arrangements with men I trust. If I should die, you will die. None of you will see the dawn.', 'Tommy Shelby', 3, 6, 'Episode 6', 'Tommy confronting enemies with a calculated insurance policy.', '{strategy,intimidation,planning}', 'threatening', 'True leverage isn''t about strength—it''s about making the cost of moving against you unacceptable. Think in systems, not single moves.'),

('a0000001-0000-0000-0000-000000000008', 'May you be in heaven a full half hour before the devil knows you''re dead.', 'Tommy Shelby', 1, 6, 'Episode 6', 'Tommy offering an Irish toast before a dangerous operation.', '{courage,humor,irish}', 'defiant', 'Move fast and execute before opposition can organize. Speed is a form of strategy—sometimes the best plan is the one that''s already done before anyone notices.'),

('a0000001-0000-0000-0000-000000000009', 'There''s a thin line between madness and strategy.', 'Tommy Shelby', 4, 6, 'The Company', 'Tommy explaining his seemingly reckless decision-making.', '{strategy,courage,risk}', 'reflective', 'What looks like madness to others is often just a level of commitment they can''t comprehend. The key is knowing which side of the line you''re actually on.'),

('a0000001-0000-0000-0000-000000000010', 'Whisky is good proofing water. It tells you who''s real and who isn''t.', 'Tommy Shelby', 2, 3, 'Episode 3', 'Tommy using a drinking session to test the loyalty of an associate.', '{loyalty,strategy,testing}', 'reflective', 'Create low-stakes tests before high-stakes trust. The small moments reveal who people really are—watch for them.'),

-- Arthur Shelby quotes
('a0000002-0000-0000-0000-000000000001', 'I''m Arthur bloody Shelby! I run the Peaky Blinders!', 'Arthur Shelby', 1, 2, 'Episode 2', 'Arthur asserting his authority during a confrontation.', '{power,identity,pride}', 'aggressive', 'There''s power in owning exactly who you are. When you stop apologizing for your identity, others stop questioning it.'),

('a0000002-0000-0000-0000-000000000002', 'We are Peaky Blinders. We are not scared of coppers. If they come for us, we will fight back.', 'Arthur Shelby', 1, 3, 'Episode 3', 'Arthur rallying the Shelby family against police threats.', '{courage,loyalty,defiance}', 'aggressive', 'Fear is a choice. When you decide as a group that you won''t be intimidated, the dynamic shifts. Unity transforms individuals into a force.'),

('a0000002-0000-0000-0000-000000000003', 'Nobody works harder than us. Nobody fights harder than us. And nobody parties harder than us.', 'Arthur Shelby', 2, 2, 'Episode 2', 'Arthur celebrating with the Shelby family after a business victory.', '{work,celebration,pride}', 'celebratory', 'Work hard, play hard isn''t a cliche when you mean it. The discipline to push harder than everyone else earns you the right to celebrate louder.'),

-- Polly Gray quotes
('a0000003-0000-0000-0000-000000000001', 'Don''t mess with the Peaky Blinders. And definitely don''t mess with Polly Gray.', 'Polly Gray', 2, 1, 'Episode 1', 'Polly making her authority clear to a newcomer.', '{power,authority,warning}', 'threatening', 'Set boundaries loudly enough that you rarely have to enforce them. A well-established reputation does more work than constant confrontation.'),

('a0000003-0000-0000-0000-000000000002', 'The only way to guarantee peace is by making the prospect of war seem hopeless.', 'Polly Gray', 3, 2, 'Episode 2', 'Polly advising Tommy on diplomatic strategy.', '{strategy,peace,wisdom}', 'reflective', 'Deterrence is the most efficient form of defense. Invest in making conflict unwinnable for your opponents, and you''ll rarely need to fight.'),

('a0000003-0000-0000-0000-000000000003', 'We women have to stick together. Men will let you down every time.', 'Polly Gray', 1, 4, 'Episode 4', 'Polly counseling a young woman about trust and self-reliance.', '{wisdom,independence,women}', 'reflective', 'Build your own support network. Depending entirely on any one person or group is a vulnerability. Diversify your trust.'),

('a0000003-0000-0000-0000-000000000004', 'I''ve buried more men than you''ve had hot dinners.', 'Polly Gray', 4, 2, 'Heathens', 'Polly reminding someone not to underestimate her experience and resolve.', '{experience,warning,toughness}', 'threatening', 'Experience is the ultimate credential. Those who''ve survived the most have earned the right to speak with authority. Respect the veterans.'),

-- Alfie Solomons quotes
('a0000004-0000-0000-0000-000000000001', 'Treachery and dishonor are not in my nature. But self-preservation is.', 'Alfie Solomons', 2, 6, 'Episode 6', 'Alfie justifying a betrayal to Tommy while acknowledging his own moral flexibility.', '{survival,honesty,pragmatism}', 'philosophical', 'Honesty about your own nature is more valuable than pretending to be noble. At least self-aware pragmatism is predictable—and predictability builds trust.'),

('a0000004-0000-0000-0000-000000000002', 'I once carried out my own form of stigmata on an Italian. I pushed his face up against a gate, right.', 'Alfie Solomons', 2, 4, 'Episode 4', 'Alfie telling a characteristically unsettling story while making a business deal.', '{intimidation,humor,violence}', 'menacing', 'Sometimes the most persuasive negotiation tool is making your counterpart deeply uncomfortable. Controlled unpredictability is a form of leverage.'),

('a0000004-0000-0000-0000-000000000003', 'War. And the men who fight in it. Are not to be f***ed with.', 'Alfie Solomons', 3, 4, 'Episode 4', 'Alfie acknowledging the shared bond and danger of men who''ve been to war.', '{war,respect,brotherhood}', 'serious', 'Shared hardship creates bonds that nothing else can replicate. Recognize and respect those who''ve been through fire—they play by different rules.'),

-- Ada Shelby quotes
('a0000005-0000-0000-0000-000000000001', 'I''m Ada Shelby, and I''m not afraid of any man.', 'Ada Shelby', 1, 4, 'Episode 4', 'Ada standing up to intimidation and asserting her independence from the family.', '{courage,independence,defiance}', 'defiant', 'Courage isn''t the absence of fear—it''s the decision that something else matters more. Declare your independence and back it up with action.'),

('a0000005-0000-0000-0000-000000000002', 'I married a man I loved, and you boys can go to hell.', 'Ada Shelby', 1, 5, 'Episode 5', 'Ada defending her marriage to Freddie Thorne against her brothers'' disapproval.', '{love,defiance,independence}', 'defiant', 'Following your own path requires the courage to disappoint people who think they know what''s best for you. Choose your own life.'),

-- Michael Gray quotes
('a0000006-0000-0000-0000-000000000001', 'I want to be part of this. Not just watching from the side.', 'Michael Gray', 2, 4, 'Episode 4', 'Michael expressing his desire to join the Shelby business rather than stay sheltered.', '{ambition,belonging,determination}', 'determined', 'Watching from the sidelines teaches you nothing about the game. At some point, you have to get your hands dirty and participate. Choose action over observation.'),

('a0000006-0000-0000-0000-000000000002', 'You''re not the only one who can make plans, Tommy.', 'Michael Gray', 5, 1, 'Black Tuesday', 'Michael challenging Tommy''s authority and revealing his own ambitions.', '{ambition,power,challenge}', 'defiant', 'Every protege eventually becomes a peer. Mentors who can''t accept this create enemies out of allies. Know when to evolve the relationship.'),

-- Grace Shelby quotes
('a0000007-0000-0000-0000-000000000001', 'If you want to be with me, you will have to let me in. All the way.', 'Grace Shelby', 1, 5, 'Episode 5', 'Grace demanding emotional honesty from Tommy as a condition of their relationship.', '{love,vulnerability,honesty}', 'earnest', 'Real connection requires real vulnerability. You can''t build deep relationships while keeping your walls up. Let people in or let them go.'),

-- Inspector Campbell quote
('a0000008-0000-0000-0000-000000000001', 'God help those who do not help themselves. Because I certainly won''t.', 'Inspector Campbell', 1, 3, 'Episode 3', 'Campbell declaring his ruthless approach to policing Birmingham.', '{authority,ruthlessness,religion}', 'cold', 'Self-reliance isn''t just a virtue—it''s a necessity. Nobody is coming to save you. Take ownership of your situation and act accordingly.'),

-- Luca Changretta quote
('a0000009-0000-0000-0000-000000000001', 'My father always said: the one who inflicts the most pain wins.', 'Luca Changretta', 4, 1, 'The Noose', 'Luca expressing his philosophy of vendetta and dominance.', '{revenge,pain,philosophy}', 'menacing', 'Endurance is a competitive advantage. The person who can absorb more punishment and keep going wins in the long run. Outlast, don''t outfight.'),

-- Billy Kimber quote
('a0000010-0000-0000-0000-000000000001', 'I am Billy Kimber! I run the races!', 'Billy Kimber', 1, 3, 'Episode 3', 'Kimber boasting about his control of the Birmingham racetracks.', '{power,arrogance,territory}', 'aggressive', 'Declaring your territory is only as powerful as your ability to defend it. Boasting without substance is just noise—make sure your claims are backed by reality.'),

-- Jessie Eden quote
('a0000011-0000-0000-0000-000000000001', 'The revolution is coming whether you like it or not, Mr. Shelby.', 'Jessie Eden', 4, 3, 'Blackbird', 'Jessie confronting Tommy about workers'' rights and social change.', '{revolution,change,defiance}', 'passionate', 'Change happens whether incumbents are ready or not. The smart move is to get ahead of the wave rather than be swept away by it. Adapt or be disrupted.'),

-- More Tommy quotes
('a0000001-0000-0000-0000-000000000011', 'Those of you who are not dead, you''d better be quiet.', 'Tommy Shelby', 1, 1, 'Episode 1', 'Tommy addressing a room after a violent confrontation.', '{authority,intimidation,calm}', 'cold', 'Composure in chaos is the ultimate display of control. When everyone around you is panicking, your calm becomes your authority.'),

('a0000001-0000-0000-0000-000000000012', 'Already, I''m thinking about everything that could go wrong. And I haven''t even started yet.', 'Tommy Shelby', 3, 4, 'Episode 4', 'Tommy reflecting on his constant state of vigilance and anxiety before a major operation.', '{planning,anxiety,strategy}', 'reflective', 'Anticipating failure isn''t pessimism—it''s preparation. The best strategists obsess over what could go wrong so they can prevent it.');

